import React, { useState } from 'react';
import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  sendPasswordResetEmail,
  sendEmailVerification,
  updateProfile,
  UserCredential
} from 'firebase/auth';
import { doc, setDoc, getDoc } from 'firebase/firestore/lite';
import { auth, db } from '../firebase';
import { Lock, Mail, Phone, User as UserIcon, AlertCircle, CheckCircle } from 'lucide-react';

interface AuthProps {
  onLoginSuccess: () => void;
}

type AuthMode = 'LOGIN' | 'SIGNUP' | 'FORGOT';

export const Auth: React.FC<AuthProps> = ({ onLoginSuccess }) => {
  const [mode, setMode] = useState<AuthMode>('LOGIN');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [phone, setPhone] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [message, setMessage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setMessage(null);
    setLoading(true);

    try {
      if (mode === 'LOGIN') {
        const userCredential = await signInWithEmailAndPassword(auth, email, password);
        const user = userCredential.user;

        // Check if user document exists, if not create it (sync legacy users or external auth)
        const userDocRef = doc(db, "users", user.uid);
        const userDoc = await getDoc(userDocRef);

        if (!userDoc.exists()) {
            await setDoc(userDocRef, {
                name: user.displayName || 'User',
                email: user.email,
                photo: user.photoURL || '',
                phone: '', 
                createdAt: new Date().toISOString()
            });
        }

        onLoginSuccess();
      } else if (mode === 'SIGNUP') {
        if (password !== confirmPassword) {
          throw new Error("Passwords do not match");
        }
        const userCredential: UserCredential = await createUserWithEmailAndPassword(auth, email, password);
        const user = userCredential.user;

        // Update Auth Profile
        await updateProfile(user, {
            displayName: fullName
        });

        // Create Firestore Document
        await setDoc(doc(db, "users", user.uid), {
            name: fullName,
            email: email,
            photo: '',
            phone: phone,
            createdAt: new Date().toISOString()
        });

        await sendEmailVerification(user);

        setMessage("Account created! Verification email sent.");
      } else if (mode === 'FORGOT') {
        await sendPasswordResetEmail(auth, email);
        setMessage("Password reset email sent! Check your inbox.");
        setMode('LOGIN');
      }
    } catch (err: any) {
      setError(err.message.replace('Firebase: ', ''));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-2xl shadow-xl overflow-hidden">
        <div className="bg-red-600 p-8 text-center text-white">
          <h1 className="text-4xl font-bold tracking-tighter mb-2">OrGo</h1>
          <p className="text-red-100 font-medium">Home Services in Jaipur</p>
        </div>

        <div className="p-8">
          <h2 className="text-2xl font-bold text-gray-800 mb-6 text-center">
            {mode === 'LOGIN' && 'Welcome Back'}
            {mode === 'SIGNUP' && 'Create Account'}
            {mode === 'FORGOT' && 'Reset Password'}
          </h2>

          {error && (
            <div className="bg-red-50 text-red-600 p-3 rounded-lg mb-4 flex items-center gap-2 text-sm">
              <AlertCircle size={16} />
              {error}
            </div>
          )}

          {message && (
            <div className="bg-green-50 text-green-600 p-3 rounded-lg mb-4 flex items-center gap-2 text-sm">
              <CheckCircle size={16} />
              {message}
            </div>
          )}

          <form onSubmit={handleAuth} className="space-y-4">
            {mode === 'SIGNUP' && (
              <>
                <div className="relative">
                  <UserIcon className="absolute left-3 top-3 text-gray-400" size={20} />
                  <input
                    type="text"
                    placeholder="Full Name"
                    className="w-full pl-10 pr-4 py-3 border rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
                    value={fullName}
                    onChange={(e) => setFullName(e.target.value)}
                    required
                  />
                </div>
                <div className="relative">
                  <Phone className="absolute left-3 top-3 text-gray-400" size={20} />
                  <input
                    type="tel"
                    placeholder="Phone (+91)"
                    className="w-full pl-10 pr-4 py-3 border rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    required
                  />
                </div>
              </>
            )}

            <div className="relative">
              <Mail className="absolute left-3 top-3 text-gray-400" size={20} />
              <input
                type="email"
                placeholder="Email Address"
                className="w-full pl-10 pr-4 py-3 border rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
              />
            </div>

            {mode !== 'FORGOT' && (
              <div className="relative">
                <Lock className="absolute left-3 top-3 text-gray-400" size={20} />
                <input
                  type="password"
                  placeholder="Password"
                  className="w-full pl-10 pr-4 py-3 border rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                />
              </div>
            )}

            {mode === 'SIGNUP' && (
              <div className="relative">
                <Lock className="absolute left-3 top-3 text-gray-400" size={20} />
                <input
                  type="password"
                  placeholder="Confirm Password"
                  className="w-full pl-10 pr-4 py-3 border rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  required
                />
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-red-600 text-white py-3 rounded-lg font-bold text-lg hover:bg-red-700 transition disabled:opacity-50"
            >
              {loading ? 'Processing...' : (
                mode === 'LOGIN' ? 'Login' : 
                mode === 'SIGNUP' ? 'Sign Up' : 'Send Reset Link'
              )}
            </button>
          </form>

          {mode === 'LOGIN' && (
            <div className="mt-4 text-center">
              <button 
                onClick={() => setMode('FORGOT')}
                className="text-red-600 text-sm font-medium hover:underline"
              >
                Forgot Password?
              </button>
            </div>
          )}

          <div className="mt-6 flex flex-col gap-3">
            {(mode === 'LOGIN' || mode === 'SIGNUP') && (
                <>
                <button type="button" className="w-full border border-gray-300 py-3 rounded-lg flex items-center justify-center gap-2 text-gray-600 hover:bg-gray-50">
                    <img src="https://www.svgrepo.com/show/475656/google-color.svg" alt="Google" className="w-5 h-5" />
                    Continue with Google
                </button>
                <button type="button" className="w-full border border-gray-300 py-3 rounded-lg flex items-center justify-center gap-2 text-gray-600 hover:bg-gray-50">
                    <img src="https://www.svgrepo.com/show/511330/apple-173.svg" alt="Apple" className="w-5 h-5" />
                    Continue with Apple
                </button>
                </>
            )}
          </div>

          <div className="mt-8 text-center text-gray-600">
            {mode === 'LOGIN' ? (
              <>
                Don't have an account?{' '}
                <button onClick={() => setMode('SIGNUP')} className="text-red-600 font-bold hover:underline">Create Account</button>
              </>
            ) : (
              <>
                Already have an account?{' '}
                <button onClick={() => setMode('LOGIN')} className="text-red-600 font-bold hover:underline">Login</button>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { User, deleteUser, updateProfile } from 'firebase/auth';
import { doc, getDoc, updateDoc, deleteDoc } from 'firebase/firestore/lite';
import { auth, db } from '../firebase';
import { 
  LogOut, 
  User as UserIcon, 
  Mail, 
  Phone, 
  Camera, 
  Edit2, 
  Save, 
  X, 
  Trash2,
  ChevronRight,
  ClipboardList,
  MapPin,
  CreditCard,
  Settings,
  HelpCircle
} from 'lucide-react';
import { AppView, UserProfile } from '../types';
import { BarChart, Bar, XAxis, Tooltip, ResponsiveContainer } from 'recharts';

interface AccountProps {
  user: User;
  onLogout: () => void;
  navigate: (view: AppView) => void;
}

const SPENDING_DATA = [
  { name: 'Aug', amount: 500 },
  { name: 'Sep', amount: 1200 },
  { name: 'Oct', amount: 450 },
];

export const Account: React.FC<AccountProps> = ({ user, onLogout, navigate }) => {
  const [loading, setLoading] = useState(true);
  const [isEditing, setIsEditing] = useState(false);
  const [profile, setProfile] = useState<UserProfile>({
    uid: user.uid,
    name: user.displayName || '',
    email: user.email || '',
    photo: '',
    phone: ''
  });
  const [editForm, setEditForm] = useState<UserProfile>(profile);

  useEffect(() => {
    const fetchProfile = async () => {
      try {
        const docRef = doc(db, 'users', user.uid);
        const docSnap = await getDoc(docRef);
        if (docSnap.exists()) {
          const data = docSnap.data() as UserProfile;
          setProfile(data);
          setEditForm(data);
        }
      } catch (error) {
        console.error("Error fetching profile:", error);
      } finally {
        setLoading(false);
      }
    };
    fetchProfile();
  }, [user.uid]);

  const handleSave = async () => {
    try {
      setLoading(true);
      const docRef = doc(db, 'users', user.uid);
      await updateDoc(docRef, {
        name: editForm.name,
        phone: editForm.phone || '',
        photo: editForm.photo || ''
      });

      if (auth.currentUser && editForm.name !== user.displayName) {
        await updateProfile(auth.currentUser, { displayName: editForm.name });
      }

      setProfile(editForm);
      setIsEditing(false);
    } catch (error) {
      console.error("Error updating profile:", error);
      alert("Failed to update profile.");
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteAccount = async () => {
    const confirm = window.confirm("Are you sure you want to permanently delete your account? This action cannot be undone.");
    if (confirm) {
      try {
        await deleteDoc(doc(db, 'users', user.uid));
        if (auth.currentUser) {
            await deleteUser(auth.currentUser);
        }
        onLogout();
      } catch (error) {
        console.error("Error deleting account:", error);
        alert("Failed to delete account. You may need to re-login.");
      }
    }
  };

  if (loading && !profile.email) return <div className="p-8 text-center text-gray-500">Loading Profile...</div>;

  return (
    <div className="pb-24 p-4">
      {/* Profile Header */}
      <div className="flex items-start justify-between mb-8 mt-4">
        <div className="flex items-center gap-4">
          <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center overflow-hidden border-2 border-red-50 relative">
             {profile.photo ? (
                <img src={profile.photo} alt="Profile" className="w-full h-full object-cover" />
             ) : (
                <span className="text-red-600 text-2xl font-bold">{profile.name ? profile.name[0].toUpperCase() : 'U'}</span>
             )}
             {isEditing && (
                 <div className="absolute inset-0 bg-black bg-opacity-30 flex items-center justify-center">
                     <Camera size={20} className="text-white" />
                 </div>
             )}
          </div>
          <div>
            {!isEditing ? (
                <>
                    <h2 className="text-xl font-bold text-gray-800">{profile.name || 'User'}</h2>
                    <p className="text-gray-500 text-sm">{profile.email}</p>
                    {profile.phone && <p className="text-gray-400 text-xs mt-1">{profile.phone}</p>}
                </>
            ) : (
                <div className="flex flex-col gap-2">
                     <input 
                        type="text" 
                        value={editForm.name} 
                        onChange={e => setEditForm({...editForm, name: e.target.value})}
                        className="border rounded px-2 py-1 text-sm font-bold w-40 focus:ring-red-500 outline-none"
                        placeholder="Name"
                     />
                     <input 
                        type="text" 
                        value={editForm.photo} 
                        onChange={e => setEditForm({...editForm, photo: e.target.value})}
                        className="border rounded px-2 py-1 text-xs w-40 focus:ring-red-500 outline-none"
                        placeholder="Photo URL"
                     />
                     <input 
                        type="tel" 
                        value={editForm.phone} 
                        onChange={e => setEditForm({...editForm, phone: e.target.value})}
                        className="border rounded px-2 py-1 text-xs w-40 focus:ring-red-500 outline-none"
                        placeholder="Phone"
                     />
                </div>
            )}
          </div>
        </div>

        {!isEditing ? (
            <button onClick={() => setIsEditing(true)} className="text-red-600 p-2 hover:bg-red-50 rounded-full">
                <Edit2 size={20} />
            </button>
        ) : (
            <div className="flex gap-2">
                <button onClick={() => setIsEditing(false)} className="text-gray-500 p-2 hover:bg-gray-100 rounded-full">
                    <X size={20} />
                </button>
                <button onClick={handleSave} disabled={loading} className="text-green-600 p-2 hover:bg-green-50 rounded-full">
                    <Save size={20} />
                </button>
            </div>
        )}
      </div>

      {/* Stats */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 mb-6">
          <h3 className="font-bold text-gray-800 mb-4">Spending Analysis</h3>
          <div className="h-40 w-full text-xs">
            <ResponsiveContainer width="100%" height="100%">
                <BarChart data={SPENDING_DATA}>
                    <XAxis dataKey="name" axisLine={false} tickLine={false} />
                    <Tooltip cursor={{fill: '#fee2e2'}} />
                    <Bar dataKey="amount" fill="#dc2626" radius={[4, 4, 0, 0]} barSize={30} />
                </BarChart>
            </ResponsiveContainer>
          </div>
      </div>

      {/* Menu Actions */}
      <div className="space-y-2 mb-8">
        {[
          { icon: ClipboardList, label: 'My Bookings', action: () => navigate(AppView.ORDERS) },
          { icon: MapPin, label: 'Saved Addresses' },
          { icon: CreditCard, label: 'Payment Methods' },
          { icon: Settings, label: 'Settings' },
          { icon: HelpCircle, label: 'Help & Support' },
        ].map((item, idx) => (
          <button 
            key={idx} 
            onClick={item.action} 
            className="w-full flex items-center justify-between p-4 bg-white rounded-xl border border-gray-100 hover:bg-gray-50 transition"
          >
             <div className="flex items-center gap-3 text-gray-700">
                <item.icon size={20} />
                <span className="font-medium">{item.label}</span>
             </div>
             <ChevronRight size={18} className="text-gray-400" />
          </button>
        ))}
      </div>

      <div className="space-y-3">
        <button onClick={onLogout} className="w-full py-3 bg-gray-200 text-gray-700 font-bold rounded-lg flex items-center justify-center gap-2 hover:bg-gray-300 transition">
            <LogOut size={20} /> Logout
        </button>

        {isEditing && (
            <button onClick={handleDeleteAccount} className="w-full py-3 bg-red-50 text-red-600 font-bold rounded-lg flex items-center justify-center gap-2 border border-red-200 hover:bg-red-100 transition">
                <Trash2 size={20} /> Delete Account
