  );
};

import React, { useState } from 'react';
import { Service, Professional } from '../types';
import { MapPin, ChevronRight, Check, Star, Ticket, Loader2 } from 'lucide-react';
import { collection, addDoc } from 'firebase/firestore/lite';
import { auth, db } from '../firebase';

interface BookingWizardProps {
  service: Service;
  onClose: () => void;
  onComplete: (bookingDetails: any) => void;
}

const PROFESSIONALS: Professional[] = [
  { id: '1', name: 'Rajesh Kumar', rating: 4.8, jobs: 120, distance: '2.5 km', eta: '15 mins', image: 'https://picsum.photos/100/100?random=1' },
  { id: '2', name: 'Amit Singh', rating: 4.6, jobs: 85, distance: '3.1 km', eta: '20 mins', image: 'https://picsum.photos/100/100?random=2' },
  { id: '3', name: 'Sunita Verma', rating: 4.9, jobs: 200, distance: '1.2 km', eta: '10 mins', image: 'https://picsum.photos/100/100?random=3' },
];

export const BookingWizard: React.FC<BookingWizardProps> = ({ service, onClose, onComplete }) => {
  const [step, setStep] = useState(1);
  const [address, setAddress] = useState('');
  const [date, setDate] = useState<string>('');
  const [timeSlot, setTimeSlot] = useState<string>('');
  const [problem, setProblem] = useState('');
  const [selectedPro, setSelectedPro] = useState<Professional | null>(null);
  const [promoCode, setPromoCode] = useState('');
  const [discount, setDiscount] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [orderId, setOrderId] = useState<string>('');

  const applyPromo = () => {
    if (promoCode.toUpperCase() === 'ORGO50') setDiscount(0.5);
    else if (promoCode.toUpperCase() === 'PLUMB100') setDiscount(0.2);
    else alert('Invalid Code');
  };

  const fees = {
    service: service.priceStart,
    travel: 50,
    gst: service.priceStart * 0.18,
  };

  const total = (fees.service + fees.travel + fees.gst) * (1 - discount);

  const handleConfirmBooking = async () => {
    if (!auth.currentUser) return;
    setIsSubmitting(true);

    try {
      const bookingData = {
        userId: auth.currentUser.uid,
        serviceName: service.name,
        serviceId: service.id,
        professionalName: selectedPro?.name || 'Assigned Professional',
        professionalId: selectedPro?.id || null,
        date,
        time: timeSlot,
        address,
        problem,
        price: Math.round(total),
        status: 'Active',
        createdAt: new Date().toISOString()
      };

      // Add to 'order' collection as requested
      const docRef = await addDoc(collection(db, 'order'), bookingData);
      setOrderId(docRef.id);
      setStep(5);
    } catch (error) {
      console.error("Error creating booking:", error);
      alert("Failed to create booking. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const renderStep1 = () => (
    <div className="space-y-6">
      <h3 className="text-xl font-bold text-gray-800">Where is the service needed?</h3>
      <div className="space-y-4">
        <button 
          onClick={() => setAddress('123, Pink City Main Rd, Raja Park, Jaipur, 302004')}
          className="w-full flex items-center gap-3 p-4 border border-red-100 bg-red-50 text-red-700 rounded-lg font-medium"
        >
          <MapPin size={20} /> Use Current Location
        </button>
        <div>
            <label className="block text-sm text-gray-600 mb-1">House/Flat No, Landmark</label>
            <textarea 
            value={address}
            onChange={(e) => setAddress(e.target.value)}
            placeholder="Enter full address in Jaipur..."
            className="w-full p-3 border rounded-lg h-24 focus:ring-2 focus:ring-red-500 focus:outline-none"
            />
        </div>
      </div>
    </div>
  );

  const renderStep2 = () => (
    <div className="space-y-6">
      <h3 className="text-xl font-bold text-gray-800">When should we come?</h3>
      <div>
        <label className="block text-sm font-medium text-gray-700 mb-2">Describe the problem</label>
        <textarea 
          value={problem}
          onChange={(e) => setProblem(e.target.value)}
          placeholder="e.g. Tap leaking continuously..."
          className="w-full p-3 border rounded-lg h-20 focus:ring-red-500 mb-4"
        />
      </div>

      <div className="grid grid-cols-3 gap-2 mb-4">
        {['Today', 'Tomorrow', 'Day After'].map((d) => (
          <button 
            key={d}
            onClick={() => setDate(d)}
            className={`p-2 rounded-lg text-sm font-medium border ${date === d ? 'bg-red-600 text-white border-red-600' : 'bg-white text-gray-700'}`}
          >
            {d}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-2 gap-2">
        {['Morning (8-11)', 'Afternoon (12-4)', 'Evening (4-8)', 'Night (8-10)'].map((t) => (
          <button 
            key={t}
            onClick={() => setTimeSlot(t)}
            className={`p-3 rounded-lg text-sm font-medium border ${timeSlot === t ? 'bg-red-600 text-white border-red-600' : 'bg-white text-gray-700'}`}
          >
            {t}
          </button>
        ))}
      </div>
    </div>
  );

  const renderStep3 = () => (
    <div className="space-y-4">
      <h3 className="text-xl font-bold text-gray-800">Select a Professional</h3>
      <div className="space-y-3">
        {PROFESSIONALS.map((pro) => (
          <div 
            key={pro.id}
            onClick={() => setSelectedPro(pro)}
            className={`flex items-center gap-4 p-4 rounded-xl border-2 cursor-pointer transition ${selectedPro?.id === pro.id ? 'border-red-600 bg-red-50' : 'border-gray-100 bg-white'}`}
          >
            <img src={pro.image} alt={pro.name} className="w-14 h-14 rounded-full object-cover" />
            <div className="flex-1">
              <h4 className="font-bold text-gray-800">{pro.name}</h4>
              <div className="flex items-center gap-2 text-sm text-gray-600">
                <span className="flex items-center text-yellow-500"><Star size={14} fill="currentColor" /> {pro.rating}</span>
                <span>• {pro.jobs} Jobs</span>
              </div>
              <div className="text-xs text-gray-500 mt-1">
                {pro.distance} away • ETA {pro.eta}
              </div>
            </div>
            {selectedPro?.id === pro.id && <Check className="text-red-600" />}
          </div>
        ))}
      </div>
    </div>
  );

  const renderStep4 = () => (
    <div className="space-y-6">
      <h3 className="text-xl font-bold text-gray-800">Payment & Review</h3>

      <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm">
        <h4 className="font-semibold mb-3">Bill Details</h4>
        <div className="space-y-2 text-sm text-gray-600">
          <div className="flex justify-between"><span>Service Fee</span><span>₹{fees.service}</span></div>
          <div className="flex justify-between"><span>Travel Fee</span><span>₹{fees.travel}</span></div>
          <div className="flex justify-between"><span>GST (18%)</span><span>₹{fees.gst.toFixed(0)}</span></div>
          {discount > 0 && (
             <div className="flex justify-between text-green-600 font-medium"><span>Discount</span><span>-₹{(fees.service + fees.travel + fees.gst) * discount}</span></div>
          )}
          <div className="border-t pt-2 mt-2 flex justify-between text-base font-bold text-gray-800">
            <span>Total To Pay</span>
            <span>₹{total.toFixed(0)}</span>
          </div>
        </div>
      </div>

      <div className="flex gap-2">
        <div className="relative flex-1">
            <Ticket className="absolute left-3 top-3 text-gray-400" size={18} />
            <input 
                type="text" 
                placeholder="Promo Code (e.g. ORGO50)" 
                value={promoCode}
                onChange={(e) => setPromoCode(e.target.value)}
                className="w-full pl-10 pr-4 py-2 border rounded-lg uppercase"
            />
        </div>
        <button onClick={applyPromo} className="bg-gray-800 text-white px-4 rounded-lg text-sm font-medium">Apply</button>
      </div>

      <div className="bg-gray-50 p-3 rounded-lg text-sm text-gray-600">
        <p><strong>Service:</strong> {service.name}</p>
        <p><strong>Address:</strong> {address}</p>
        <p><strong>Time:</strong> {date}, {timeSlot}</p>
        <p><strong>Pro:</strong> {selectedPro?.name}</p>
      </div>
    </div>
  );

  const renderSuccess = () => (
    <div className="flex flex-col items-center justify-center py-10 text-center">
      <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mb-6">
        <Check className="text-green-600" size={40} />
      </div>
      <h2 className="text-2xl font-bold text-gray-800 mb-2">Booking Confirmed!</h2>
      <p className="text-gray-600 mb-8">Booking ID: #{orderId.slice(0, 8).toUpperCase()}</p>

      <div className="w-full space-y-3">
        <button onClick={() => onComplete({id: orderId, status: 'Active'})} className="w-full py-3 bg-red-600 text-white rounded-lg font-bold">
          Track Order
        </button>
        <button onClick={onClose} className="w-full py-3 border border-gray-300 text-gray-600 rounded-lg font-medium">
          Back to Home
        </button>
      </div>
    </div>
  );

  return (
    <div className="fixed inset-0 bg-white z-50 flex flex-col">
      <div className="bg-red-600 p-4 text-white flex items-center gap-3 shadow-md">
        <button onClick={onClose} className="hover:bg-red-700 p-1 rounded">Back</button>
        <h2 className="text-lg font-bold flex-1">Book {service.name}</h2>
        <span className="text-sm opacity-80">Step {step}/4</span>
      </div>

      <div className="flex-1 overflow-y-auto p-4 pb-20">
        {step === 1 && renderStep1()}
        {step === 2 && renderStep2()}
        {step === 3 && renderStep3()}
        {step === 4 && renderStep4()}
        {step === 5 && renderSuccess()}
      </div>

      {step < 5 && (
        <div className="p-4 border-t bg-white safe-area-bottom">
          <button 
            disabled={
              isSubmitting ||
              (step === 1 && !address) || 
              (step === 2 && (!date || !timeSlot)) ||
              (step === 3 && !selectedPro)
            }
            onClick={() => step === 4 ? handleConfirmBooking() : setStep(s => s + 1)}
            className="w-full bg-red-600 text-white py-3 rounded-lg font-bold text-lg disabled:opacity-50 flex items-center justify-center gap-2"
          >
            {isSubmitting ? (
              <>Processing <Loader2 className="animate-spin" size={20} /></>
            ) : (
              step === 4 ? 'Confirm Booking' : 
              <>Next Step <ChevronRight size={20} /></>
            )}
          </button>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { auth, db } from './firebase';
import { onAuthStateChanged, User, signOut } from 'firebase/auth';
import { collection, query, where, getDocs } from 'firebase/firestore/lite';
import { Auth } from './components/Auth';
import { BookingWizard } from './components/BookingWizard';
import { Tracking } from './components/Tracking';
import { Account } from './components/Account';
import { Service, AppView, Booking } from './types';
import { 
  Home, 
  ClipboardList, 
  Tag, 
  MapPin, 
  User as UserIcon, 
  Wrench, 
  Droplet, 
  Hammer, 
  Zap, 
  Truck, 
  Scissors, 
  Search, 
  Menu,
  Copy,
  Star,
  RefreshCw
} from 'lucide-react';

const SERVICES: Service[] = [
  { id: '1', name: 'Appliance Repair', icon: 'wrench', priceStart: 299 },
  { id: '2', name: 'Plumbing', icon: 'droplet', priceStart: 199 },
  { id: '3', name: 'Carpentry', icon: 'hammer', priceStart: 349 },
  { id: '4', name: 'Electrical', icon: 'zap', priceStart: 249 },
  { id: '5', name: 'Vehicle Repair', icon: 'truck', priceStart: 499 },
  { id: '6', name: 'Gardening', icon: 'scissors', priceStart: 399 },
  { id: '7', name: 'Cleaning', icon: 'search', priceStart: 499 },
  { id: '8', name: 'Painting', icon: 'brush', priceStart: 999 },
];

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [view, setView] = useState<AppView>(AppView.HOME);
  const [selectedService, setSelectedService] = useState<Service | null>(null);
  const [orders, setOrders] = useState<Booking[]>([]);
  const [loadingOrders, setLoadingOrders] = useState(false);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
      setLoading(false);
      if (!currentUser) setView(AppView.AUTH);
      else if (view === AppView.AUTH) setView(AppView.HOME);
    });
    return () => unsubscribe();
  }, [view]);

  useEffect(() => {
    if (user && view === AppView.ORDERS) {
      fetchOrders();
    }
  }, [user, view]);

  const fetchOrders = async () => {
    if (!user) return;
    setLoadingOrders(true);
    try {
      const q = query(collection(db, 'order'), where('userId', '==', user.uid));
      const querySnapshot = await getDocs(q);
      const fetchedOrders: Booking[] = [];
      querySnapshot.forEach((doc) => {
        const data = doc.data();
        fetchedOrders.push({
          id: doc.id,
          serviceName: data.serviceName,
          professionalName: data.professionalName,
          date: data.date,
          time: data.time,
          status: data.status,
          price: data.price,
          address: data.address
        });
      });
      setOrders(fetchedOrders);
    } catch (error) {
      console.error("Error fetching orders:", error);
    } finally {
      setLoadingOrders(false);
    }
  };

  const handleServiceClick = (service: Service) => {
    setSelectedService(service);
    setView(AppView.BOOKING);
  };

  const handleBookingComplete = () => {
    setView(AppView.TRACKING);
    setSelectedService(null);
    fetchOrders(); // Refresh orders after new booking
  };

  const handleLogout = async () => {
    await signOut(auth);
    setUser(null);
    setView(AppView.AUTH);
  };

  if (loading) return <div className="h-screen flex items-center justify-center text-red-600 font-bold">Loading OrGo...</div>;

  if (!user) return <Auth onLoginSuccess={() => setView(AppView.HOME)} />;

  if (view === AppView.BOOKING && selectedService) {
    return (
      <BookingWizard 
        service={selectedService} 
        onClose={() => setView(AppView.HOME)} 
        onComplete={handleBookingComplete} 
      />
    );
  }

  // --- Views ---

  const renderHome = () => (
    <div className="pb-24">
      {/* Location Bar */}
      <div className="bg-red-600 text-white p-4 pt-4 pb-6 rounded-b-3xl shadow-lg sticky top-0 z-20">
        <div className="flex items-center justify-between mb-2">
            <h1 className="font-extrabold text-2xl tracking-tighter">OrGo</h1>
            <Menu size={24} />
        </div>
        <div className="flex items-center gap-2 bg-red-700 bg-opacity-50 p-2 rounded-lg cursor-pointer">
          <MapPin size={18} className="text-red-200" />
          <div className="flex-1">
            <p className="text-xs text-red-200 font-medium">Location</p>
            <p className="font-bold text-sm flex items-center gap-1">Jaipur, Rajasthan <span className="rotate-90">›</span></p>
          </div>
        </div>
      </div>

      <div className="p-4 space-y-6 -mt-4 relative z-10">
        {/* Hero Banner */}
        <div className="bg-gradient-to-r from-red-500 to-orange-500 rounded-2xl p-5 text-white shadow-lg shadow-red-200">
          <p className="font-medium opacity-90 mb-1">New in Jaipur?</p>
          <h2 className="text-2xl font-bold mb-3 leading-tight">Get 50% OFF on your first booking!</h2>
          <div className="inline-block bg-white text-red-600 px-3 py-1 rounded border-2 border-dashed border-red-200 font-mono font-bold text-sm">
            Use Code: ORGO50
          </div>
        </div>

        {/* Services Grid */}
        <div>
          <h3 className="text-xl font-bold text-gray-800 mb-4">What do you need help with?</h3>
          <div className="grid grid-cols-3 gap-3">
            {SERVICES.map((s) => (
              <div 
                key={s.id} 
                onClick={() => handleServiceClick(s)}
                className="bg-white p-3 rounded-xl shadow-sm border border-gray-100 flex flex-col items-center justify-center text-center gap-2 active:scale-95 transition"
              >
                <div className="bg-red-50 p-3 rounded-full text-red-600">
                  {s.icon === 'wrench' && <Wrench size={20} />}
                  {s.icon === 'droplet' && <Droplet size={20} />}
                  {s.icon === 'hammer' && <Hammer size={20} />}
                  {s.icon === 'zap' && <Zap size={20} />}
                  {s.icon === 'truck' && <Truck size={20} />}
                  {s.icon === 'scissors' && <Scissors size={20} />}
                  {s.icon === 'search' && <Search size={20} />}
                  {s.icon === 'brush' && <div className="w-5 h-5 bg-red-600 rounded-full" />}
                </div>
                <p className="text-xs font-semibold text-gray-700 leading-tight">{s.name}</p>
                <p className="text-[10px] text-gray-400">From ₹{s.priceStart}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );

  const renderOrders = () => (
    <div className="pb-24 p-4">
      <div className="flex items-center justify-between mb-6 mt-2">
        <h2 className="text-2xl font-bold text-gray-800">My Bookings</h2>
        <button onClick={fetchOrders} disabled={loadingOrders} className="p-2 text-red-600 hover:bg-red-50 rounded-full">
            <RefreshCw size={20} className={loadingOrders ? "animate-spin" : ""} />
        </button>
      </div>

      {orders.length === 0 && !loadingOrders ? (
        <div className="text-center py-10 text-gray-500">
            <ClipboardList size={48} className="mx-auto mb-4 opacity-20" />
            <p>No active bookings yet.</p>
        </div>
      ) : (
        <div className="space-y-4">
            {orders.map((order) => (
            <div key={order.id} className="bg-white rounded-xl p-4 shadow-sm border border-gray-200">
                <div className="flex justify-between items-start mb-3">
                <div>
                    <h3 className="font-bold text-lg text-gray-800">{order.serviceName}</h3>
                    <p className="text-sm text-gray-500">{order.professionalName}</p>
                </div>
                <span className={`px-2 py-1 rounded text-xs font-bold ${order.status === 'Active' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-600'}`}>
                    {order.status}
                </span>
                </div>
                <div className="text-sm text-gray-600 space-y-1 mb-4">
                <p>{order.date} • {order.time}</p>
                <p className="truncate">{order.address}</p>
                <p className="font-bold text-gray-900">₹{order.price}</p>
                </div>
                <div className="flex gap-3 pt-3 border-t">
                {order.status === 'Active' ? (
                    <>
                    <button onClick={() => setView(AppView.TRACKING)} className="flex-1 py-2 bg-red-600 text-white rounded-lg text-sm font-medium">Track</button>
                    <button className="flex-1 py-2 border border-red-200 text-red-600 rounded-lg text-sm font-medium">Cancel</button>
                    </>
                ) : (
                    <button className="flex-1 py-2 border border-gray-300 text-gray-700 rounded-lg text-sm font-medium flex items-center justify-center gap-2">
                        <Star size={16} /> Rate Pro
                    </button>
                )}
                </div>
            </div>
            ))}
        </div>
      )}
    </div>
  );

  const renderOffers = () => (
    <div className="pb-24">
      <div className="bg-red-600 text-white p-6 rounded-b-3xl mb-6">
        <h2 className="text-2xl font-bold mb-2">Exclusive Jaipur Offers</h2>
        <p className="opacity-90">Save big on your home services today</p>
      </div>
      <div className="px-4 space-y-4">
        {[
          { code: 'ORGO50', title: '50% OFF First Booking', desc: 'Max discount ₹200. Valid for new users.' },
          { code: 'PLUMB100', title: 'Flat ₹100 OFF', desc: 'On all plumbing services above ₹499.' },
          { code: 'FREECALL', title: 'Free Consultation', desc: 'Get expert advice for free via chat.' },
        ].map((offer) => (
          <div key={offer.code} className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm relative overflow-hidden">
            <div className="absolute -right-4 -top-4 bg-yellow-400 w-16 h-16 rounded-full opacity-20"></div>
            <h3 className="font-bold text-lg text-red-600 mb-1">{offer.title}</h3>
            <p className="text-sm text-gray-600 mb-3">{offer.desc}</p>
            <div className="flex items-center justify-between bg-gray-50 p-2 rounded-lg border border-dashed border-gray-300">
              <code className="font-bold text-gray-800">{offer.code}</code>
              <button className="text-xs font-bold text-red-600 flex items-center gap-1 uppercase">
                <Copy size={12} /> Copy
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50 font-sans max-w-md mx-auto shadow-2xl relative overflow-hidden">
      {/* Content Area */}
      <div className="h-full overflow-y-auto no-scrollbar bg-gray-50 min-h-screen">
        {view === AppView.HOME && renderHome()}
        {view === AppView.ORDERS && renderOrders()}
        {view === AppView.OFFERS && renderOffers()}
        {view === AppView.TRACKING && <Tracking />}
        {view === AppView.ACCOUNT && user && (
            <Account user={user} onLogout={handleLogout} navigate={setView} />
        )}
      </div>

      {/* Bottom Navigation */}
      <div className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white border-t border-gray-200 flex justify-around py-3 pb-safe z-30 shadow-[0_-5px_10px_rgba(0,0,0,0.05)]">
        <button onClick={() => setView(AppView.HOME)} className={`flex flex-col items-center gap-1 ${view === AppView.HOME ? 'text-red-600' : 'text-gray-400'}`}>
          <Home size={24} strokeWidth={view === AppView.HOME ? 3 : 2} />
          <span className="text-[10px] font-medium">Home</span>
        </button>
        <button onClick={() => setView(AppView.ORDERS)} className={`flex flex-col items-center gap-1 ${view === AppView.ORDERS ? 'text-red-600' : 'text-gray-400'}`}>
          <ClipboardList size={24} strokeWidth={view === AppView.ORDERS ? 3 : 2} />
          <span className="text-[10px] font-medium">Orders</span>
        </button>
        <button onClick={() => setView(AppView.OFFERS)} className={`flex flex-col items-center gap-1 ${view === AppView.OFFERS ? 'text-red-600' : 'text-gray-400'}`}>
          <Tag size={24} strokeWidth={view === AppView.OFFERS ? 3 : 2} />
          <span className="text-[10px] font-medium">Offers</span>
        </button>
        <button onClick={() => setView(AppView.TRACKING)} className={`flex flex-col items-center gap-1 ${view === AppView.TRACKING ? 'text-red-600' : 'text-gray-400'}`}>
          <MapPin size={24} strokeWidth={view === AppView.TRACKING ? 3 : 2} />
          <span className="text-[10px] font-medium">Track</span>
        </button>
        <button onClick={() => setView(AppView.ACCOUNT)} className={`flex flex-col items-center gap-1 ${view === AppView.ACCOUNT ? 'text-red-600' : 'text-gray-400'}`}>
          <UserIcon size={24} strokeWidth={view === AppView.ACCOUNT ? 3 : 2} />
          <span className="text-[10px] font-medium">Account</span>
        </button>
      </div>
    </div>
  );
};

export default App;
